#include <bits/stdc++.h>
using namespace std;
const int N=15;
long long c[N][N],f[N],mi[N],s[10];
void init(){
    for(int i=0;i<N;i++)
        for(int j=0;j<=i;j++)
            c[i][j]=(!j?1:c[i-1][j]+c[i-1][j-1]);
    mi[0]=1;
    for(int i=1;i<N;i++){
        mi[i]=mi[i-1]*10;
        long long p=1;
        for(int j=i;j;j--,p*=9)
            f[i]+=c[i][j]*j*p;
    }
}
void ans(long long x,int xs){
    if(!x)
        return;
    int n=0,a[N];
    while(x)
        a[++n]=x%10,x/=10;
    for(int i=n;i;i--){
        for(int j=0;j<a[i];j++){
            s[j]+=xs*mi[i-1];
            for(int k=0;k<=9;k++)
                s[k]+=xs*f[i-1];
        }
    }
    for(int i=1;i<=n;i++)
        s[a[i]]+=xs;
    long long sum=0;
    for(int i=1;i<n;i++){
        sum=sum+a[i]*mi[i-1];
        s[a[i+1]]+=sum*xs,s[0]-=xs*mi[i];
    }
    s[0]-=xs;
}
int main(){
    init();
    long long l,r;
    scanf("%lld%lld",&l,&r);
    ans(r,1),ans(l-1,-1);
    for(int i=0;i<=9;i++)
        printf("%lld ",s[i]);
    return 0;
}
